#include <iostream>
#include <fstream>
#include <cmath>
#include <omp.h>

#define MAX_THREADS_PER_BLOCK 512

struct Node {
    int starting;
    int no_of_edges;
};

void BFSGraph(int argc, char** argv);

int main(int argc, char** argv) {
    BFSGraph(argc, argv);
    return 0;
}

void Usage(int argc, char** argv) {
    std::cerr << "Usage: " << argv[0] << " <input_file>" << std::endl;
}

void BFSGraph(int argc, char** argv) {
    char* input_f;
    if (argc != 2) {
        Usage(argc, argv);
        exit(0);
    }

    input_f = argv[1];
    std::cout << "Reading File" << std::endl;
    std::ifstream fp(input_f);
    if (!fp) {
        std::cout << "Error Reading graph file" << std::endl;
        return;
    }

    int no_of_nodes;
    fp >> no_of_nodes;

    int num_of_blocks = 1;
    int num_of_threads_per_block = no_of_nodes;

    if (no_of_nodes > MAX_THREADS_PER_BLOCK) {
        num_of_blocks = (int)ceil(no_of_nodes / (double)MAX_THREADS_PER_BLOCK);
        num_of_threads_per_block = MAX_THREADS_PER_BLOCK;
    }

    Node* h_graph_nodes = new Node[no_of_nodes];
    bool* h_graph_mask = new bool[no_of_nodes];
    bool* h_updating_graph_mask = new bool[no_of_nodes];
    bool* h_graph_visited = new bool[no_of_nodes];

    int start, edgeno;
    for (unsigned int i = 0; i < no_of_nodes; i++) {
        fp >> start >> edgeno;
        h_graph_nodes[i].starting = start;
        h_graph_nodes[i].no_of_edges = edgeno;
        h_graph_mask[i] = false;
        h_updating_graph_mask[i] = false;
        h_graph_visited[i] = false;
    }

    int source = 0;
    fp >> source;
    source = 0;

    h_graph_mask[source] = true;
    h_graph_visited[source] = true;

    int edge_list_size;
    fp >> edge_list_size;

    int* h_graph_edges = new int[edge_list_size];
    for (int i = 0; i < edge_list_size; i++) {
        int id, cost;
        fp >> id >> cost;
        h_graph_edges[i] = id;
    }

    fp.close();

    std::cout << "Read File" << std::endl;

    int* h_cost = new int[no_of_nodes];
    for (int i = 0; i < no_of_nodes; i++)
        h_cost[i] = -1;
    h_cost[source] = 0;

    bool stop = false;
    int k = 0;
    std::cout << "Start traversing the tree" << std::endl;
    do {
        stop = false;
#pragma omp parallel for num_threads(num_of_threads_per_block)
        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (tid < no_of_nodes && h_graph_mask[tid]) {
                h_graph_mask[tid] = false;
                for (int i = h_graph_nodes[tid].starting; i < (h_graph_nodes[tid].no_of_edges + h_graph_nodes[tid].starting); i++) {
                    int id = h_graph_edges[i];
                    if (!h_graph_visited[id]) {
                        h_cost[id] = h_cost[tid] + 1;
                        h_updating_graph_mask[id] = true;
                    }
                }
            }
        }

#pragma omp parallel for num_threads(num_of_threads_per_block)
        for (int tid = 0; tid < no_of_nodes; tid++) {
            if (tid < no_of_nodes && h_updating_graph_mask[tid]) {
                h_graph_mask[tid] = true;
                h_graph_visited[tid] = true;
                stop = true;
                h_updating_graph_mask[tid] = false;
            }
        }

        k++;
    } while (stop);

    std::cout << "Kernel Executed " << k << " times" << std::endl;

    std::ofstream fpo("result.txt");
    for (int i = 0; i < no_of_nodes; i++)
        fpo << i << ") cost:" << h_cost[i] << std::endl;
    fpo.close();
    std::cout << "Result stored in result.txt" << std::endl;
    std::cout << "BFS traversal completed and results written to file" << std::endl;

    delete[] h_graph_nodes;
    delete[] h_graph_edges;
    delete[] h_graph_mask;
    delete[] h_updating_graph_mask;
    delete[] h_graph_visited;
    delete[] h_cost;
}
